test('_executeToolBatch pauses remaining clicks when API replay is available', async () => {
  for (const AgentClass of [AgentCh, AgentFx]) {
    const agent = new AgentClass({ getVisionProvider: async () => null });
    const tabId = 2062;
    const apiMap = new Map([[tabId, []]]);
    const executed = [];
    const updates = [];
    const messages = [];
    const originalApiRequests = globalThis.__webbrainApiRequests;
    globalThis.__webbrainApiRequests = apiMap;

    try {
      agent._ensureGateSetting = async () => {};
      agent._skipPermissionGate = true;
      agent._currentUrl = async () => 'https://github.com/acme/repo/stargazers';
      agent._recordProgressObservation = async () => null;
      agent._autoRecordProgressAction = () => null;
      agent._progressWarningForAction = () => '';
      agent._persist = () => {};
      agent.setApiMutationsAllowed(tabId, true);
      agent.executeTool = async (_tabId, name, args) => {
        assert.equal(name, 'click_ax', `${AgentClass.name}: unexpected tool`);
        const target = `user${executed.length}`;
        executed.push(args.ref_id);
        apiMap.get(tabId).push({
          url: `https://github.com/users/follow?target=${target}`,
          method: 'POST',
          ts: Date.now(),
          replayRequestId: `api_${target}`,
          hasBody: true,
          headerNames: ['content-type', 'accept'],
        });
        return { success: true, method: 'click_ax', ref_id: args.ref_id, name: `Follow ${target}` };
      };
      const toolCalls = Array.from({ length: 10 }, (_, i) => ({
        id: `click_${i}`,
        function: {
          name: 'click_ax',
          arguments: JSON.stringify({ ref_id: `ref_${i}` }),
        },
      }));

      const result = await agent._executeToolBatch(
        tabId,
        toolCalls,
        messages,
        (type, data) => updates.push({ type, data }),
        { supportsVision: false },
        '',
        new Set(['click_ax']),
        3,
      );

      assert.equal(result.action, 'continue', `${AgentClass.name}: interrupted batch should continue to next model turn`);
      assert.deepEqual(executed, ['ref_0', 'ref_1'], `${AgentClass.name}: should execute only until replay shortcut is detected`);
      assert.equal(messages.length, 10, `${AgentClass.name}: every tool call needs a tool result`);
      assert.match(messages[1].content, /BULK API MUTATION PATTERN/, `${AgentClass.name}: triggering click result missed replay warning`);
      assert.match(messages[1].content, /Stop further same-shape UI clicks/, `${AgentClass.name}: warning should instruct a replay pivot`);
      const skipped = messages.slice(2).map(msg => JSON.parse(msg.content));
      assert.equal(skipped.length, 8, `${AgentClass.name}: expected eight skipped calls`);
      assert.ok(skipped.every(item => item.skipped === true && item.skippedBecause === 'bulk_api_replay_available'), `${AgentClass.name}: skipped calls missing replay marker`);
      assert.ok(updates.some(update => update.type === 'warning' && /paused 8 remaining/.test(update.data?.message || '')), `${AgentClass.name}: missing batch pause warning`);
    } finally {
      if (originalApiRequests === undefined) delete globalThis.__webbrainApiRequests;
      else globalThis.__webbrainApiRequests = originalApiRequests;
    }
  }
});

test('failed API replay suppresses future bulk replay hints until a success clears it', () => {
  for (const AgentClass of [AgentCh, AgentFx]) {
    const agent = new AgentClass({});
    const tabId = 2063;
    const base = Date.now();
    const requests = [];
    const apiMap = new Map([[tabId, requests]]);
    const originalApiRequests = globalThis.__webbrainApiRequests;
    globalThis.__webbrainApiRequests = apiMap;
    agent.setApiMutationsAllowed(tabId, true);

    const click = (i, target) => {
      requests.push({
        url: `https://github.com/users/follow?target=${target}`,
        method: 'POST',
        ts: base + (i * 1000) + 20,
        replayRequestId: `api_${target}`,
      });
      return agent._detectBulkApiMutationShortcut(
        tabId,
        'click_ax',
        { ref_id: `ref_${i}` },
        { success: true, name: `Follow ${target}` },
        { startedAt: base + (i * 1000), endedAt: base + (i * 1000) + 100, pageUrl: 'https://github.com/acme/repo/stargazers' },
      );
    };

    try {
      assert.equal(click(0, 'alice'), null, `${AgentClass.name}: first click should not hint`);
      assert.ok(click(1, 'bob'), `${AgentClass.name}: second click should hint`);

      const failed = agent._trackBulkApiReplayResult(
        tabId,
        'fetch_url',
        { url: 'https://github.com/users/follow?target=carol', method: 'POST', replayRequestId: 'api_carol' },
        { success: false, status: 422, error: 'Fetch returned HTTP 422' },
      );
      assert.equal(failed.failed, true, `${AgentClass.name}: failed replay was not tracked`);
      assert.equal(click(2, 'carol'), null, `${AgentClass.name}: failed shape should suppress future replay hints`);

      const cleared = agent._trackBulkApiReplayResult(
        tabId,
        'fetch_url',
        { url: 'https://github.com/users/follow?target=dave', method: 'POST', replayRequestId: 'api_dave' },
        { success: true, status: 200, text: 'ok' },
      );
      assert.equal(cleared.failed, false, `${AgentClass.name}: successful replay should clear failed shape`);
      assert.ok(click(3, 'dave'), `${AgentClass.name}: cleared shape should become eligible again`);
    } finally {
      if (originalApiRequests === undefined) delete globalThis.__webbrainApiRequests;
      else globalThis.__webbrainApiRequests = originalApiRequests;
    }
  }
});
//
// These mirror the static helpers on Agent exactly — keep them in sync
// with src/chrome/src/agent/agent.js `_estimateImageTokens` and
// `_fitImageDimensions`. We shim rather than import because agent.js
// pulls in chrome.* and cdp-client.
// ────────────────────────────────────────────────────────────────────────

const IMAGE_BUDGET_DEFAULT = {
  pxPerToken: 28,
  maxTargetPx: 1568,
  maxTargetTokens: 1568,
};

function estimateImageTokens(w, h, pxPerToken) {
  return Math.ceil((w / pxPerToken) * (h / pxPerToken));
}

function fitImageDimensions(origW, origH, budget = IMAGE_BUDGET_DEFAULT) {
  const { pxPerToken, maxTargetPx, maxTargetTokens } = budget;
  if (origW <= maxTargetPx && origH <= maxTargetPx &&
      estimateImageTokens(origW, origH, pxPerToken) <= maxTargetTokens) {
    return [origW, origH];
  }
  if (origH > origW) {
    const [h, w] = fitImageDimensions(origH, origW, budget);
    return [w, h];
  }
  const aspect = origW / origH;
  let hi = origW, lo = 1;
  while (true) {
    if (lo + 1 >= hi) return [lo, Math.max(Math.round(lo / aspect), 1)];
    const mid = Math.floor((lo + hi) / 2);
    const midH = Math.max(Math.round(mid / aspect), 1);
    if (mid <= maxTargetPx &&
        estimateImageTokens(mid, midH, pxPerToken) <= maxTargetTokens) {
      lo = mid;
    } else {
      hi = mid;
    }
  }
}

console.log('\nimage budget');

test('small viewport passes through unchanged (fast path)', () => {
  // 1280×800 at pxPerToken=28 → 1307 tokens < 1568 — no resize.
  const [w, h] = fitImageDimensions(1280, 800);
  assert.equal(w, 1280);
  assert.equal(h, 800);
});

test('1080p shrinks to fit the token cap', () => {
  // 1920×1080 → 2645 tokens (over). Target keeps aspect at ~1.78.
  const [w, h] = fitImageDimensions(1920, 1080);
  assert.ok(w <= 1568, `width ${w} > 1568`);
  assert.ok(h <= 1568, `height ${h} > 1568`);
  assert.ok(estimateImageTokens(w, h, 28) <= 1568, `tokens over cap: ${estimateImageTokens(w, h, 28)}`);
  // Aspect ratio preserved within 1 pixel (rounding).
  const origAspect = 1920 / 1080;
  const newAspect = w / h;
  assert.ok(Math.abs(origAspect - newAspect) < 0.01, `aspect drift ${newAspect} vs ${origAspect}`);
});

test('4K and 1440p converge to the same max-budget dims', () => {
  // Any input with the same 16:9 aspect ratio should produce the same
  // largest-that-fits output. Catches off-by-one regressions in the
  // binary search.
  const [w1440, h1440] = fitImageDimensions(2560, 1440);
  const [w4k, h4k] = fitImageDimensions(3840, 2160);
  assert.equal(w1440, w4k);
  assert.equal(h1440, h4k);
});

test('visible media localization parser accepts fenced JSON and clamps to viewport', () => {
  const raw = '```json\n{"found":true,"x":-10,"y":20,"right":330,"bottom":220,"confidence":87,"mediaType":"image"}\n```';
  for (const AgentClass of [AgentCh, AgentFx]) {
    const rect = AgentClass._normalizeVisibleMediaLocation(raw, { width: 300, height: 200 });
    assert.deepEqual(rect, {
      found: true,
      x: 0,
      y: 20,
      width: 300,
      height: 180,
      confidence: 0.87,
      mediaType: 'image',
      reason: '',
    });
  }
});

test('visible media localization parser rejects no-target and tiny boxes', () => {
  for (const AgentClass of [AgentCh, AgentFx]) {
    assert.equal(AgentClass._normalizeVisibleMediaLocation('{"found":false}', { width: 300, height: 200 }), null);
    assert.equal(AgentClass._normalizeVisibleMediaLocation('{"found":true,"x":10,"y":10,"width":10,"height":10}', { width: 300, height: 200 }), null);
  }
});

test('tall portrait caps the long side at maxTargetPx', () => {
  // A 1920×8000 full-page capture — the long side here is height.
  const [w, h] = fitImageDimensions(1920, 8000);
  assert.ok(h <= 1568, `height ${h} > 1568`);
  assert.ok(w > 0, 'width should be positive');
  assert.ok(estimateImageTokens(w, h, 28) <= 1568);
});

test('high-DPR 5K viewport stays within budget', () => {
  // 5120×2880 (retina 5K). Should fit token cap after resize.
  const [w, h] = fitImageDimensions(5120, 2880);
  assert.ok(w <= 1568);
  assert.ok(h <= 1568);
  assert.ok(estimateImageTokens(w, h, 28) <= 1568);
});

test('square input returns a square that fits', () => {
  const [w, h] = fitImageDimensions(3000, 3000);
  assert.ok(w <= 1568);
  assert.ok(h <= 1568);
  // Square in, square (within 1 px) out.
  assert.ok(Math.abs(w - h) <= 1);
});

test('pathological 1×100000 strip does not blow up', () => {
  // Edge case: an extremely thin strip. The binary search used to have
  // a termination bug when origH >> origW; this locks in that fix.
  const [w, h] = fitImageDimensions(1, 100000);
  assert.ok(h <= 1568);
  assert.ok(w >= 1);
  assert.ok(estimateImageTokens(w, h, 28) <= 1568);
});

test('custom budget is honored', () => {
  // Shrink to a tight 400 token / 400 px budget — no dimension should exceed.
  const [w, h] = fitImageDimensions(1920, 1080, {
    pxPerToken: 28, maxTargetPx: 400, maxTargetTokens: 400,
  });
  assert.ok(w <= 400);
  assert.ok(h <= 400);
  assert.ok(estimateImageTokens(w, h, 28) <= 400);
});

test('existing dims under caps stay within the monotonic bound', () => {
  // Fuzz a range of common viewport sizes; invariant: output ≤ input on
  // every dimension, and output token count ≤ maxTargetTokens.
  const inputs = [
    [1366, 768], [1440, 900], [1680, 1050], [1600, 900], [1920, 1200],
    [2048, 1152], [2304, 1440], [2560, 1600], [2880, 1800],
  ];
  for (const [iw, ih] of inputs) {
    const [ow, oh] = fitImageDimensions(iw, ih);
    assert.ok(ow <= iw, `w grew: ${iw}→${ow}`);
    assert.ok(oh <= ih, `h grew: ${ih}→${oh}`);
    assert.ok(estimateImageTokens(ow, oh, 28) <= 1568, `tokens over cap for ${iw}×${ih} → ${ow}×${oh}`);
  }
});

