test('API mutation observer setting is opt-in and controls the request observer', () => {
  for (const [label, bgRel, settingsRel, htmlRel] of [
    ['chrome', 'src/chrome/src/background.js', 'src/chrome/src/ui/settings.js', 'src/chrome/src/ui/settings.html'],
    ['firefox', 'src/firefox/src/background.js', 'src/firefox/src/ui/settings.js', 'src/firefox/src/ui/settings.html'],
  ]) {
    const bg = fs.readFileSync(path.join(ROOT, bgRel), 'utf8');
    const settings = fs.readFileSync(path.join(ROOT, settingsRel), 'utf8');
    const html = fs.readFileSync(path.join(ROOT, htmlRel), 'utf8');

    assert.match(html, /id="toggle-api-mutation-observer"/, `${label}: settings toggle missing`);
    assert.doesNotMatch(html, /id="toggle-api-mutation-observer"\s+checked/, `${label}: observer toggle should default off`);
    assert.match(settings, /apiMutationObserverEnabled/, `${label}: settings should persist observer toggle`);
    assert.match(settings, /apiMutationObserverToggle\.checked = stored\.apiMutationObserverEnabled === true/, `${label}: observer should load off by default`);
    assert.match(settings, /apiMutationObserverEnabled:\s*apiMutationObserverToggle\.checked/, `${label}: observer toggle should save storage`);
    assert.match(bg, /const API_MUTATION_OBSERVER_KEY = 'apiMutationObserverEnabled';/, `${label}: storage key missing`);
    assert.match(bg, /const API_MUTATION_OBSERVER_DEFAULT = false;/, `${label}: observer default should be explicit and off`);
    assert.match(bg, /function setApiMutationObserverEnabled\(enabled\)/, `${label}: observer gate missing`);
    assert.doesNotMatch(bg, /(?:chrome|browser)\.webRequest\.onBeforeRequest\.addListener\(/, `${label}: observer should not register unconditionally`);
    assert.match(bg, /onBeforeRequest\.addListener\(recordApiRequest/, `${label}: observer should register only through the gate`);
    assert.match(bg, /onBeforeRequest\.addListener\(recordApiRequest[\s\S]*\['requestBody'\]/, `${label}: observer should capture request bodies for opaque replay`);
    assert.match(bg, /onBeforeSendHeaders\?\.addListener\(\s*recordApiRequestHeaders/, `${label}: observer should capture replay-safe request headers`);
    assert.match(bg, /globalThis\.__webbrainApiRequestReplay = apiRequestReplayById/, `${label}: replay store should be available to fetch_url`);
    assert.match(bg, /onBeforeRequest\.removeListener\(recordApiRequest\)/, `${label}: observer should unregister when disabled`);
    assert.match(bg, /onBeforeSendHeaders\?\.removeListener\(recordApiRequestHeaders\)/, `${label}: header observer should unregister when disabled`);
    assert.match(bg, /storage\.local\.get\(\{ \[API_MUTATION_OBSERVER_KEY\]: API_MUTATION_OBSERVER_DEFAULT \}\)/, `${label}: unset storage should use explicit off default`);
    assert.match(bg, /setApiMutationObserverEnabled\(stored\[API_MUTATION_OBSERVER_KEY\] === true\)/, `${label}: only explicit true should enable observer`);
    assert.match(
      bg,
      /changes\[API_MUTATION_OBSERVER_KEY\][\s\S]*setApiMutationObserverEnabled\(changes\[API_MUTATION_OBSERVER_KEY\]\.newValue === true\)/,
      `${label}: storage changes should update observer`,
    );
  }
});

test('settings async test controls surface rejected background results', () => {
  for (const [label, settingsRel, htmlRel] of [
    ['chrome', 'src/chrome/src/ui/settings.js', 'src/chrome/src/ui/settings.html'],
    ['firefox', 'src/firefox/src/ui/settings.js', 'src/firefox/src/ui/settings.html'],
  ]) {
    const settings = fs.readFileSync(path.join(ROOT, settingsRel), 'utf8');
    const html = fs.readFileSync(path.join(ROOT, htmlRel), 'utf8');

    assert.match(
      settings,
      /function showVisionResult\(className, text, color = ''\) \{[\s\S]*?visionTestResult\.style\.color = color \|\| '';[\s\S]*?return visionTestResult;[\s\S]*?\}/,
      `${label}: vision status helper should clear stale inline colors and return the current node`,
    );
    assert.match(
      settings,
      /function showTranscriptionResult\(className, text, color = ''\) \{[\s\S]*?if \(!transcriptionTestResult\) return;[\s\S]*?transcriptionTestResult\.style\.color = color \|\| '';[\s\S]*?return transcriptionTestResult;[\s\S]*?\}/,
      `${label}: transcription status helper should clear stale inline colors and tolerate absent controls`,
    );
    assert.match(
      settings,
      /function showCaptchaResult\(className, text, color = ''\) \{[\s\S]*?if \(!captchaTestResult\) return;[\s\S]*?captchaTestResult\.style\.color = color \|\| '';[\s\S]*?return captchaTestResult;[\s\S]*?\}/,
      `${label}: captcha status helper should clear stale inline colors and tolerate absent controls`,
    );

    const visionStart = settings.indexOf("btnTestVision.addEventListener('click', async () => {");
    assert.notEqual(visionStart, -1, `${label}: vision test handler missing`);
    const visionBody = settings.slice(visionStart, settings.indexOf('\n});\n\nbtnClearVision', visionStart) + 4);
    assert.match(
      visionBody,
      /showVisionResult\('', t\('st\.vision\.testing'\), 'var\(--text2\)'\);[\s\S]*?try \{[\s\S]*?const res = await sendToBackground\('test_vision_provider'\);[\s\S]*?showVisionResult\('ok'[\s\S]*?showVisionResult\('fail'[\s\S]*?\} catch \(e\) \{[\s\S]*?showVisionResult\('fail', t\('st\.vision\.failed', \{ error: e\.message \}\)\);[\s\S]*?\}/,
      `${label}: rejected vision provider checks should replace the testing state with a failure`,
    );

    const transcriptionStart = settings.indexOf("btnTestTranscription.addEventListener('click', async () => {");
    assert.notEqual(transcriptionStart, -1, `${label}: transcription test handler missing`);
    const transcriptionEnd = settings.indexOf('\n  });\n}\n\nif (btnClearTranscription', transcriptionStart);
    assert.notEqual(transcriptionEnd, -1, `${label}: transcription test handler boundary missing`);
    const transcriptionBody = settings.slice(transcriptionStart, transcriptionEnd + 7);
    assert.match(
      transcriptionBody,
      /showTranscriptionResult\('', t\('st\.transcription\.testing'\), 'var\(--text2\)'\);[\s\S]*?try \{[\s\S]*?const res = await sendToBackground\('test_transcription_provider'\);[\s\S]*?showTranscriptionResult\('ok'[\s\S]*?showTranscriptionResult\('fail'[\s\S]*?\} catch \(e\) \{[\s\S]*?showTranscriptionResult\('fail', t\('st\.transcription\.failed', \{ error: e\.message \}\)\);[\s\S]*?\}/,
      `${label}: rejected transcription provider checks should replace the testing state with a failure`,
    );

    const captchaStart = settings.indexOf("btnTestCaptcha.addEventListener('click', async () => {");
    assert.notEqual(captchaStart, -1, `${label}: captcha test handler missing`);
    const captchaEnd = settings.indexOf('\n  });\n}\n\nif (btnClearCaptcha', captchaStart);
    assert.notEqual(captchaEnd, -1, `${label}: captcha test handler boundary missing`);
    const captchaBody = settings.slice(captchaStart, captchaEnd + 7);
    assert.match(
      captchaBody,
      /showCaptchaResult\('', t\('st\.captcha\.checking'\), 'var\(--text2\)'\);[\s\S]*?try \{[\s\S]*?const res = await sendToBackground\('test_capsolver_balance', \{ apiKey: key \}\);[\s\S]*?flashCaptchaResult\('ok'[\s\S]*?flashCaptchaResult\('fail'[\s\S]*?\} catch \(e\) \{[\s\S]*?flashCaptchaResult\('fail', t\('st\.captcha\.balance_fail', \{ error: e\.message \}\)\);[\s\S]*?\}/,
      `${label}: rejected captcha balance checks should replace the checking state with a failure`,
    );

    assert.match(
      settings,
      /function setProviderLoadModelsStatus\(id, message, color = 'var\(--text2\)'\) \{[\s\S]*?document\.querySelector\(`\.load-models-status\[data-provider="\$\{id\}"\]`\);[\s\S]*?statusEl\.textContent = message;[\s\S]*?statusEl\.style\.color = color;[\s\S]*?return statusEl;[\s\S]*?\}/,
      `${label}: model-load status writes should re-query the current provider card`,
    );

    const loadStart = settings.indexOf('async function loadProviderModels(id) {');
    assert.notEqual(loadStart, -1, `${label}: loadProviderModels missing`);
    const loadBody = settings.slice(loadStart, settings.indexOf('\n}\n\nfunction setProviderTestResult', loadStart) + 2);
    assert.match(
      loadBody,
      /let datalistEl = document\.getElementById\(`models-\$\{id\}`\);[\s\S]*?await saveProvider\(id, \{ showFlash: false, markConfigured: false \}\);[\s\S]*?\} catch \(e\) \{[\s\S]*?setProviderLoadModelsStatus\(id, providerModelLoadErrorMessage\(e\.message\), 'var\(--danger, #c33\)'\);[\s\S]*?return;[\s\S]*?setProviderLoadModelsStatus\(id, t\('st\.providers\.loading'\)\);[\s\S]*?try \{[\s\S]*?res = await sendToBackground\('list_provider_models', \{ providerId: id \}\);[\s\S]*?\} catch \(e\) \{[\s\S]*?setProviderLoadModelsStatus\(id, providerModelLoadErrorMessage\(e\.message\), 'var\(--danger, #c33\)'\);[\s\S]*?return;[\s\S]*?\}[\s\S]*?datalistEl = document\.getElementById\(`models-\$\{id\}`\);[\s\S]*?if \(!datalistEl\) return;[\s\S]*?setProviderLoadModelsStatus\(id, providerModelLoadErrorMessage\(res\), 'var\(--danger, #c33\)'\);/,
      `${label}: model loading should report rejected background results and avoid stale datalist writes`,
    );
    assert.match(
      settings,
      /function providerModelLoadErrorMessage\(resultOrError\) \{[\s\S]*?resultOrError\?\.errorKey[\s\S]*?t\(resultOrError\.errorKey\)[\s\S]*?\^HTTP\\s\+404\\b[\s\S]*?<!doctype\\s\+html\|<html\[\\s>\]\|file not found[\s\S]*?t\('ob\.tokens\.none_status'\)[\s\S]*?\}/,
      `${label}: HTML 404 model-list failures should be shown as a concise local-server status`,
    );
    assert.match(
      settings,
      /function clearProviderLoadedModels\(id\) \{[\s\S]*?loadedDialogEl\.querySelector\('\.loaded-model-options'\);[\s\S]*?optionsEl\.innerHTML = '';[\s\S]*?closeLoadedModelDialog\(loadedDialogEl\);[\s\S]*?if \(datalistEl\) datalistEl\.innerHTML = '';[\s\S]*?\}/,
      `${label}: model loading should have a helper that clears stale loaded-model choices`,
    );
    assert.match(
      loadBody,
      /let datalistEl = document\.getElementById\(`models-\$\{id\}`\);[\s\S]*?if \(!datalistEl\) return;[\s\S]*?clearProviderLoadedModels\(id\);[\s\S]*?await saveProvider\(id, \{ showFlash: false, markConfigured: false \}\);/,
      `${label}: model loading should clear stale model choices before saving or requesting new models`,
    );
    assert.match(
      settings,
      /const loadedModelsDialogHTML = canLoadModels[\s\S]*<dialog class="loaded-model-dialog" data-loaded-models-for="\$\{id\}"[\s\S]*class="loaded-model-options"[\s\S]*\$\{loadedModelsDialogHTML\}/,
      `${label}: local model loading should render a loaded-model dialog`,
    );
    assert.doesNotMatch(
      settings,
      /loaded-model-select|loadedModelsSelectHTML|loaded-model-menu|loadedModelsMenuHTML/,
      `${label}: local model loading should not render a second select control or inline menu`,
    );
    assert.match(
      loadBody,
      /const loadedDialogEl = document\.querySelector\(`\.loaded-model-dialog\[data-loaded-models-for="\$\{id\}"\]`\);[\s\S]*?const optionsEl = loadedDialogEl\.querySelector\('\.loaded-model-options'\);[\s\S]*?optionsEl\.innerHTML = res\.models[\s\S]*?class="loaded-model-option"[\s\S]*?if \(res\.models\.length\) openLoadedModelDialog\(loadedDialogEl\);/,
      `${label}: loaded models should populate and open a dialog without replacing the current model text`,
    );
    assert.doesNotMatch(
      loadBody,
      /input\.value\s*=\s*res\.models/,
      `${label}: loading models should not overwrite an existing model until the user chooses one`,
    );
    assert.match(
      settings,
      /document\.querySelectorAll\('\.loaded-model-dialog'\)\.forEach\(dialog => \{[\s\S]*?dialog\.addEventListener\('click', \(event\) => \{[\s\S]*?event\.target === dialog[\s\S]*?closeLoadedModelDialog\(dialog\);[\s\S]*?event\.target\.closest\('\.loaded-model-option'\);[\s\S]*?const providerId = dialog\.dataset\.loadedModelsFor;[\s\S]*?const selectedModel = option\.dataset\.model \|\| '';[\s\S]*?input\.value = selectedModel;[\s\S]*?saveProvider\(providerId, \{ showFlash: false \}\)[\s\S]*?detectProviderContextWindowForModel\(providerId, selectedModel\)[\s\S]*?closeLoadedModelDialog\(dialog\);[\s\S]*?\}\);[\s\S]*?\}\);/,
      `${label}: choosing a loaded model should save it before detecting context for that model`,
    );
    assert.match(
      settings,
      /async function detectProviderContextWindowForModel\(id, model\) \{[\s\S]*?sendToBackground\('detect_provider_context_window', \{ providerId: id, model: value \}\);[\s\S]*?applyProviderContextWindow\(id, res\.contextWindow\);[\s\S]*?\}/,
      `${label}: selected-model context detection should update the provider context field`,
    );
    assert.match(
      settings,
      /function openLoadedModelDialog\(dialog\) \{[\s\S]*?if \(!dialog\) return;[\s\S]*?if \(dialog\.open\) return;[\s\S]*?dialog\.showModal/,
      `${label}: loaded-model dialog opening should tolerate repeated model-load responses`,
    );
    assert.match(
      html,
      /\.loaded-model-dialog \{[\s\S]*?position: fixed;[\s\S]*?inset: 0;[\s\S]*?margin: auto;[\s\S]*?width: min\(520px, calc\(100vw - 32px\)\);/,
      `${label}: loaded-model dialog should stay centered despite the global margin reset`,
    );
    const localeDir = path.join(ROOT, label === 'chrome' ? 'src/chrome/src/ui/locales' : 'src/firefox/src/ui/locales');
    for (const filename of fs.readdirSync(localeDir).filter((name) => name.endsWith('.js'))) {
      const locale = fs.readFileSync(path.join(localeDir, filename), 'utf8');
      assert.match(
        locale,
        /['"]st\.providers\.select_loaded_model['"]:\s*['"][^'"]+['"]/,
        `${label}/${filename}: loaded-model selector copy should be localized`,
      );
    }
  }
});

test('settings waits for immediate preference writes and theme persistence', () => {
  for (const [label, settingsRel] of [
    ['chrome', 'src/chrome/src/ui/settings.js'],
    ['firefox', 'src/firefox/src/ui/settings.js'],
  ]) {
    const settings = fs.readFileSync(path.join(ROOT, settingsRel), 'utf8');
    assert.match(
      settings,
      /themeSelect\.addEventListener\('change', async \(\) => \{[\s\S]*?await applyMode\(mode\);[\s\S]*?\}\);/,
      `${label}: theme selection should await persistence`,
    );
    assert.match(
      settings,
      /profileEnabledToggle\.addEventListener\('change', async \(\) => \{[\s\S]*?await (chrome|browser)\.storage\.local\.set\(\{ profileEnabled: profileEnabledToggle\.checked \}\)\.catch\(\(\) => \{\}\);[\s\S]*?\}\);/,
      `${label}: profile toggle should await persistence`,
    );
    assert.match(
      settings,
      /captchaEnabledToggle\.addEventListener\('change', async \(\) => \{[\s\S]*?await (chrome|browser)\.storage\.local\.set\(\{ captchaSolverEnabled: captchaEnabledToggle\.checked \}\)\.catch\(\(\) => \{\}\);[\s\S]*?\}\);/,
      `${label}: captcha toggle should await persistence`,
    );
    assert.match(
      settings,
      /btn\.addEventListener\('click', async \(\) => \{[\s\S]*?await (chrome|browser)\.storage\.local\.set\(\{ providerFilter: f\.key \}\)\.catch\(\(\) => \{\}\);[\s\S]*?renderProviders\(\);[\s\S]*?\}\);/,
      `${label}: provider filter clicks should await persistence before rerendering`,
    );

    const theme = fs.readFileSync(path.join(ROOT, label === 'chrome' ? 'src/chrome/src/ui/theme.js' : 'src/firefox/src/ui/theme.js'), 'utf8');
    assert.match(
      theme,
      /export async function applyMode\(mode, opts = \{\}\) \{[\s\S]*?await (chrome|browser)\.storage\.local\.set\(\{ themeMode: mode \}\)\.catch\(\(\) => \{\}\);[\s\S]*?\}/,
      `${label}: shared theme helper should await storage persistence`,
    );

    const i18n = fs.readFileSync(path.join(ROOT, label === 'chrome' ? 'src/chrome/src/ui/i18n.js' : 'src/firefox/src/ui/i18n.js'), 'utf8');
    assert.match(
      i18n,
      /export async function setLocale\(code\) \{[\s\S]*?await api\?\.storage\?\.local\?\.set\?\.?\(\{ wbLocale: code \}\);[\s\S]*?applyDOMTranslations\(document\);/,
      `${label}: locale helper should await storage persistence before broadcasting`,
    );
    assert.match(
      settings,
      /languageSelect\.addEventListener\('change', async \(\) => \{[\s\S]*?await setLocale\(languageSelect\.value\);[\s\S]*?renderSubtitle\(\);/,
      `${label}: settings language change should await locale persistence`,
    );
  }
});

