test('TSV roundtrip: 100 random shapes', () => {
  const shapes = [
    [['a']],
    [['a','b','c']],
    [['a'],['b'],['c']],
    [['x\ty','z']],
    [['line1\nline2','plain']],
    [['has "quotes"','none']],
    [['',''],['',''],['','']],
    [['1','2','3'],['4','5','6']],
  ];
  for (const grid of shapes) {
    const tsv = valuesToTsv(grid);
    const back = tsvToValues(tsv);
    assert.deepEqual(back, grid, `roundtrip failed for ${JSON.stringify(grid)}`);
  }
});

