test('exhaustiveness: every model-exposed tool is classified', () => {
  for (const [label, getTools, capFor] of [
    ['firefox', getToolsForModeFx, capabilityFor],
    ['chrome', getToolsForModeCh, capabilityForCh],
  ]) {
    const tools = getTools('act');
    // Guard against a vacuous pass (e.g. getTools returning []).
    assert.ok(tools.length >= 15, `[${label}] expected the act toolset, got ${tools.length} tools`);
    for (const t of tools) {
      const name = t.function?.name;
      if (!name) continue;
      const gated = capFor(name, {}) !== null;       // has a (possible) side effect
      const untrustedRead = UNTRUSTED_CONTENT_TOOLS.has(name); // result is page-derived
      const knownSafe = KNOWN_SAFE_TOOLS.has(name);
      assert.ok(
        gated || untrustedRead || knownSafe,
        `[${label}] tool "${name}" is unclassified. Add it to capabilityFor() if it has a side effect, ` +
        `UNTRUSTED_CONTENT_TOOLS if its result is page-derived, or the KNOWN_SAFE_TOOLS allowlist (with justification).`
      );
    }
  }
});

test('planner: parse and format structured plan', () => {
  const raw = JSON.stringify({
    summary: 'Follow GitHub stargazers',
    confidence: 92,
    steps: [{ id: '1', action: 'Open stargazers', tools: ['navigate', 'wait_for_stable'] }],
    memory: {
      use_scratchpad: true,
      scratchpad_notes: ['download IDs'],
      use_progress_ledger: true,
      progress_action: 'follow',
    },
    scheduling: { tool: 'schedule_task', hint: 'user asked for daily check' },
    risks: ['bulk follow'],
    mode: 'act',
  });
  const plan = parsePlanFromContent(raw);
  assert.ok(plan, 'should parse JSON plan');
  assert.equal(plan.summary, 'Follow GitHub stargazers');
  assert.equal(plan.confidence, 0.92);
  assert.equal(plan.memory.use_progress_ledger, true);
  assert.equal(plan.scheduling.tool, 'schedule_task');
  const md = formatPlanMarkdown(plan);
  assert.match(md, /Follow GitHub stargazers/, 'compact plan should keep the summary');
  assert.match(md, /1\. Open stargazers/);
  assert.doesNotMatch(md, /navigate|wait_for_stable/, 'compact plan should hide tool names');
  assert.doesNotMatch(md, /Progress ledger|Scratchpad|schedule_task|bulk follow/, 'compact plan should hide planner internals');
  const verboseMd = formatPlanMarkdown(plan, { verbose: true });
  assert.match(verboseMd, /Confidence: 92%/);
  assert.match(verboseMd, /navigate, wait_for_stable/);
  assert.match(verboseMd, /Progress ledger: yes/);
  assert.match(verboseMd, /schedule_task/);
  const scratch = formatPlanScratchpad(plan);
  assert.match(scratch, /\[Approved plan/);
});

