test('plan before act: try is default while explicit off is preserved', () => {
  for (const [label, AgentClass] of [['chrome', AgentCh], ['firefox', AgentFx]]) {
    const agent = new AgentClass({});
    assert.equal(agent.planBeforeActMode, 'try', `${label} default mode`);
    assert.equal(agent.planBeforeAct, true, `${label} legacy mirror default`);
    assert.equal(agent._plannerMode(), 'try', `${label} effective default mode`);
    assert.equal(agent.planReviewMode, 'confidence', `${label} default plan review mode`);
    assert.equal(agent.planReviewConfidenceThreshold, 0.75, `${label} default plan review threshold`);
    assert.equal(agent._shouldReviewPlan({ confidence: 0.74 }), true, `${label} default below-threshold plans should review`);
    assert.equal(agent._shouldReviewPlan({ confidence: 0.75 }), false, `${label} default at-threshold plans should auto-approve`);
    agent.setPlanReviewSettings({ mode: 'always', confidenceThreshold: 95 });
    assert.equal(agent.planReviewMode, 'always', `${label} review mode setter`);
    assert.equal(agent.planReviewConfidenceThreshold, 0.95, `${label} review threshold percent setter`);
    assert.equal(agent._shouldReviewPlan({ confidence: 1 }), true, `${label} always mode should review high-confidence plans`);
    agent.setPlanReviewSettings({ mode: 'never', confidenceThreshold: 0.9 });
    assert.equal(agent._shouldReviewPlan({ confidence: 0.1 }), false, `${label} never mode should auto-approve low-confidence plans`);
    agent.setPlanReviewSettings({ mode: 'confidence', confidenceThreshold: 0.9 });
    assert.equal(agent._shouldReviewPlan({ confidence: 0.89 }), true, `${label} below-threshold plans should review`);
    assert.equal(agent._shouldReviewPlan({ confidence: 0.9 }), false, `${label} at-threshold plans should auto-approve`);
    agent.setPlanReviewSettings({ confidenceThreshold: 0 });
    assert.equal(agent.planReviewConfidenceThreshold, 0.5, `${label} out-of-band low threshold clamps to the slider floor`);
    agent.setPlanReviewSettings({ confidenceThreshold: 1 });
    assert.equal(agent.planReviewConfidenceThreshold, 0.99, `${label} out-of-band high threshold clamps to the slider ceiling`);
    agent.setPlanReviewSettings({ confidenceThreshold: 0.9 });
    agent.setPlanBeforeActMode('try');
    assert.equal(agent.planBeforeAct, true, `${label} try enables legacy mirror`);
    assert.equal(agent._plannerMode(), 'try', `${label} try mode`);
    agent.setPlanBeforeActMode('strict');
    assert.equal(agent.planBeforeAct, true, `${label} strict enables legacy mirror`);
    assert.equal(agent._plannerMode(), 'strict', `${label} strict mode`);
    agent.setPlanBeforeActMode('off');
    assert.equal(agent.planBeforeAct, false, `${label} off disables legacy mirror`);
    assert.equal(agent._plannerMode(), 'off', `${label} off mode`);
  }
  for (const file of [
    'src/chrome/src/background.js',
    'src/firefox/src/background.js',
    'src/chrome/src/ui/settings.js',
    'src/firefox/src/ui/settings.js',
  ]) {
    const source = fs.readFileSync(path.join(ROOT, file), 'utf8');
    assert.match(source, /planBeforeActMode/, `${file} should use the planner mode setting`);
    assert.match(source, /return 'try'/, `${file} should treat unset storage as planning try`);
    assert.match(source, /planBeforeAct(?:Mode)?[^]*?=== false[^]*?return 'off'/, `${file} should preserve explicit legacy off storage`);
    assert.match(source, /planBeforeAct(?:Mode)?[^]*?=== true[^]*?return 'strict'/, `${file} should migrate legacy enabled storage to strict`);
  }
  for (const file of [
    'src/chrome/src/background.js',
    'src/firefox/src/background.js',
    'src/chrome/src/ui/settings.js',
    'src/firefox/src/ui/settings.js',
  ]) {
    const source = fs.readFileSync(path.join(ROOT, file), 'utf8');
    assert.match(source, /planReviewMode/, `${file} should persist the plan review mode setting`);
    assert.match(source, /planReviewConfidenceThreshold/, `${file} should persist the plan review confidence threshold`);
  }
  for (const file of [
    'src/chrome/src/ui/settings.html',
    'src/firefox/src/ui/settings.html',
  ]) {
    const html = fs.readFileSync(path.join(ROOT, file), 'utf8');
    assert.match(html, /<select id="select-plan-before-act-mode">\s*<option value="try"/, `${file} should render try as the first/default option`);
    assert.match(html, /<select id="select-plan-review-mode">\s*<option value="confidence"/, `${file} should render confidence review as the first/default option`);
    assert.match(html, /id="range-plan-review-confidence"/, `${file} should expose the confidence threshold slider`);
    assert.match(html, /id="range-plan-review-confidence"[^>]*value="75"/, `${file} should render the 75% default threshold`);
  }
  for (const file of [
    'src/chrome/src/ui/locales/en.js',
    'src/firefox/src/ui/locales/en.js',
  ]) {
    const locale = fs.readFileSync(path.join(ROOT, file), 'utf8');
    assert.match(locale, /Try mode is the default/, `${file} should describe try planning as the default`);
    assert.match(locale, /'st\.display\.plan_before_act\.try': 'Try planning \(default\)'/, `${file} should label try planning as default`);
    assert.match(locale, /'st\.display\.plan_before_act\.off': 'Off'/, `${file} should not label off as default`);
    assert.doesNotMatch(locale, /plan_before_act\.desc[^\n]*Off by default/, `${file} should not describe plan-before-act as off by default`);
    assert.doesNotMatch(locale, /plan_before_act\.off': 'Off \(default\)'/, `${file} should not mark off as default`);
  }
});

