test('planner gate: retries reasoning-only planner responses for final JSON', async () => {
  await withPlannerBrowserGlobals(async () => {
    for (const [label, AgentClass] of [['chrome', AgentCh], ['firefox', AgentFx]]) {
      const tabId = label === 'chrome' ? 9171 : 9172;
      const provider = {
        name: 'vllm',
        model: 'qwen3-test',
        config: { providerName: 'vllm', category: 'local' },
      };
      const agent = new AgentClass({ getActive: () => provider });
      agent.conversations.set(tabId, [{ role: 'system', content: 'system' }]);
      agent.setScheduledRunPolicy(tabId, {
        requireConsequentialConfirmation: false,
        autoApprovePlanReview: true,
      });
      let calls = 0;
      const seen = [];
      agent._chatWithCostAllowance = async (_provider, messages, options) => {
        calls += 1;
        seen.push({ messages, options });
        if (calls === 1) {
          return {
            content: '',
            reasoningContent: 'The plan is clear, but no final JSON was emitted.',
            raw: { choices: [{ message: { reasoning_content: 'hidden reasoning only' } }] },
          };
        }
        return { content: plannerFixtureJson() };
      };

      const gate = await agent._runPlannerGate(
        tabId,
        { role: 'user', content: 'schedule a task in 2 minutes' },
        () => {},
        null,
      );

      assert.equal(gate.proceed, true, `${label} should recover with a valid plan`);
      assert.equal(calls, 2, `${label} should retry exactly once`);
      assert.match(seen[0].messages.find((m) => m.role === 'user').content, /^\/no_think/, `${label} should use no-think mode for Qwen-style planner models`);
      assert.equal(seen[0].options.maxTokens, 4096, `${label} should give the planner enough final-token budget`);
      assert.equal(seen[0].options.extraBody?.chat_template_kwargs?.enable_thinking, false, `${label} should disable vLLM/SGLang thinking`);
      assert.match(seen[1].messages.at(-1).content, /\/no_think/, `${label} repair prompt should request no-think mode`);
    }
  });
});

test('planner gate: approving plan appends without deleting scratchpad facts', async () => {
  await withPlannerBrowserGlobals(async () => {
    for (const [label, AgentClass] of [['chrome', AgentCh], ['firefox', AgentFx]]) {
      const tabId = label === 'chrome' ? 9201 : 9202;
      const agent = new AgentClass({ getActive: () => ({}) });
      agent.setPlanBeforeActMode('try');
      agent.setPlanReviewSettings({ confidenceThreshold: 0.9 });
      agent.conversations.set(tabId, [
        { role: 'system', content: 'system' },
        { role: 'user', content: 'original task' },
      ]);
      agent._scratchpadWrite(tabId, { text: '[auto] Existing downloadId=42 for report.pdf' });
      agent._chatWithCostAllowance = async () => ({ content: plannerFixtureJson() });
      agent._waitForPlanReview = async () => ({ action: 'approve', editedText: '' });

      const messages = agent.conversations.get(tabId);
      const enriched = { role: 'user', content: 'collect account links' };
      const outcome = await agent._maybeRunPlannerGate(
        tabId, messages, enriched, () => {}, 'act', null, null,
      );
      assert.equal(outcome.proceed, true, `${label} should proceed`);

      const idx = agent._findScratchpadIndex(agent.conversations.get(tabId));
      const body = agent._extractScratchpadBody(agent.conversations.get(tabId)[idx].content);
      assert.match(body, /Existing downloadId=42/, `${label} should preserve existing scratchpad fact`);
      assert.match(body, /\[Approved plan — pinned by planner\]/, `${label} should append approved plan marker`);
      assert.match(body, /read_page/, `${label} unedited approval should pin verbose tool detail for execution`);
      assert.match(body, /Scratchpad: yes/, `${label} unedited approval should pin verbose memory strategy for execution`);

      const userIdx = agent.conversations.get(tabId).findIndex((m) => m.role === 'user' && m.content === 'collect account links');
      assert.ok(userIdx >= 0, `${label} user message present`);
      assert.ok(idx > userIdx, `${label} scratchpad should follow user task`);
      assert.equal(idx, agent.conversations.get(tabId).length - 1, `${label} scratchpad should be last`);
    }
  });
});

test('planner gate: trusted recommended media action skips planner and pins ready plan', async () => {
  await withPlannerBrowserGlobals(async () => {
    for (const [label, AgentClass, prefix] of [['chrome', AgentCh, 'src/chrome'], ['firefox', AgentFx, 'src/firefox']]) {
      const tabId = label === 'chrome' ? 9207 : 9208;
      const agent = new AgentClass({ getActive: () => ({}) });
      agent.setCustomSkills([packagedFreeSkillzRecord(prefix)]);
      agent.setPlanBeforeActMode('strict');
      agent.setPlanReviewSettings({ mode: 'always' });
      agent.conversations.set(tabId, [{ role: 'system', content: 'system' }]);
      let plannerCalls = 0;
      agent._runPlannerGate = async () => {
        plannerCalls += 1;
        throw new Error('recommended action fast path should not call planner');
      };

      const outcome = await agent._maybeRunPlannerGate(
        tabId,
        agent.conversations.get(tabId),
        { role: 'user', content: 'Download this public media from the current page.' },
        () => {},
        'act',
        null,
        null,
        null,
        {
          recommendedAction: {
            id: 'download-media',
            skipPlanner: true,
            tool: 'download_public_media',
            summary: 'Download the public media from the current page.',
            steps: [
              'Call download_public_media with kind:"video" and no url so it uses the active tab.',
              'Report the saved downloadId/result.',
            ],
          },
        },
      );

      assert.equal(outcome.proceed, true, `${label} should proceed`);
      assert.equal(plannerCalls, 0, `${label} should skip the planner call`);
      assert.equal(agent.plannerFollowUpSkipTabs.has(tabId), false, `${label} should not arm the ordinary planner follow-up skip`);

      const messages = agent.conversations.get(tabId);
      const idx = agent._findScratchpadIndex(messages);
      assert.ok(idx >= 0, `${label} should pin a recommended-action scratchpad plan`);
      const body = agent._extractScratchpadBody(messages[idx].content);
      assert.match(body, /\[Approved plan — pinned by recommended action\]/, `${label} should mark first-party recommended plan`);
      assert.match(body, /download_public_media/, `${label} should pin the intended immediate tool`);
      assert.doesNotMatch(body, /pinned by planner/, `${label} should not pretend a planner generated this`);
      const userIdx = messages.findIndex((m) => m.role === 'user' && /Download this public media/.test(m.content));
      assert.ok(idx > userIdx, `${label} scratchpad should follow the user task`);

      const rejectedTabId = tabId + 20;
      const rejected = new AgentClass({ getActive: () => ({}) });
      rejected.setPlanBeforeActMode('try');
      rejected.conversations.set(rejectedTabId, [{ role: 'system', content: 'system' }]);
      let fallbackPlannerCalls = 0;
      rejected._runPlannerGate = async () => {
        fallbackPlannerCalls += 1;
        return { proceed: true };
      };
      const rejectedOutcome = await rejected._maybeRunPlannerGate(
        rejectedTabId,
        rejected.conversations.get(rejectedTabId),
        { role: 'user', content: 'Do something else.' },
        () => {},
        'act',
        null,
        null,
        null,
        {
          recommendedAction: {
            id: 'download-media',
            skipPlanner: true,
            tool: 'download_social_media',
            summary: 'Invalid fast path.',
          },
        },
      );
      assert.equal(rejectedOutcome.proceed, true, `${label} rejected fast path should still proceed through normal planner`);
      assert.equal(fallbackPlannerCalls, 1, `${label} rejected fast path should run planner`);

      const noSkillTabId = tabId + 40;
      const noSkillAgent = new AgentClass({ getActive: () => ({}) });
      noSkillAgent.setCustomSkills([]);
      noSkillAgent.setPlanBeforeActMode('try');
      noSkillAgent.conversations.set(noSkillTabId, [{ role: 'system', content: 'system' }]);
      let noSkillPlannerCalls = 0;
      noSkillAgent._runPlannerGate = async () => {
        noSkillPlannerCalls += 1;
        return { proceed: true };
      };
      const noSkillOutcome = await noSkillAgent._maybeRunPlannerGate(
        noSkillTabId,
        noSkillAgent.conversations.get(noSkillTabId),
        { role: 'user', content: 'Download this public media from the current page.' },
        () => {},
        'act',
        null,
        null,
        null,
        {
          recommendedAction: {
            id: 'download-media',
            skipPlanner: true,
            tool: 'download_public_media',
            summary: 'Download the public media from the current page.',
          },
        },
      );
      assert.equal(noSkillOutcome.proceed, true, `${label} missing skill should still proceed through normal planner`);
      assert.equal(noSkillPlannerCalls, 1, `${label} missing skill should run planner`);
    }
  });
});

test('recommended action first tools are allowlisted and sanitized', () => {
  for (const [label, AgentClass, prefix] of [['chrome', AgentCh, 'src/chrome'], ['firefox', AgentFx, 'src/firefox']]) {
    const agent = new AgentClass({ getActive: () => ({}) });
    const allowed = new Set(['read_page', 'get_accessibility_tree', 'read_youtube_transcript', 'click_ax']);

    assert.deepEqual(
      agent._recommendedActionFirstTool({
        recommendedAction: {
          id: 'summarize-page',
          autoExecute: true,
          tool: 'read_page',
          args: { includeChrome: false, maxDepth: 999 },
        },
      }, allowed),
      { id: 'summarize-page', tool: 'read_page', args: { includeChrome: false } },
      `${label}: read_page args should be sanitized`,
    );

    assert.deepEqual(
      agent._recommendedActionFirstTool({
        recommendedAction: {
          id: 'explain-page',
          autoExecute: true,
          tool: 'get_accessibility_tree',
          args: { filter: 'visible', maxDepth: 99, maxChars: 999999, ref_id: 'ref_1' },
        },
      }, allowed),
      { id: 'explain-page', tool: 'get_accessibility_tree', args: { filter: 'visible', maxDepth: 20, maxChars: 60000 } },
      `${label}: accessibility tree args should be allowlisted and clamped`,
    );

    assert.equal(
      agent._recommendedActionFirstTool({
        recommendedAction: { id: 'summarize-page', autoExecute: true, tool: 'click_ax', args: { ref_id: 'ref_1' } },
      }, allowed),
      null,
      `${label}: state-changing tools must not be accepted as recommended first tools`,
    );

    assert.equal(
      agent._recommendedActionFirstTool({
        recommendedAction: { id: 'summarize-youtube-video', autoExecute: true, tool: 'read_youtube_transcript', args: {} },
      }, allowed),
      null,
      `${label}: transcript first tool should require the enabled skill`,
    );

    agent.setCustomSkills([packagedFreeSkillzRecord(prefix)]);
    assert.deepEqual(
      agent._recommendedActionFirstTool({
        recommendedAction: {
          id: 'summarize-youtube-video',
          autoExecute: true,
          tool: 'read_youtube_transcript',
          args: { timestamps: true, include_segments: false, text_limit: 99999, url: 'https://youtu.be/abc' },
        },
      }, allowed),
      {
        id: 'summarize-youtube-video',
        tool: 'read_youtube_transcript',
        args: { timestamps: true, include_segments: false, text_limit: 12000 },
      },
      `${label}: transcript args should be sanitized and omit client URL`,
    );
  }
});

test('recommended action first tool executes before first model call', async () => {
  await withPlannerBrowserGlobals(async () => {
    for (const [label, AgentClass] of [['chrome', AgentCh], ['firefox', AgentFx]]) {
      const tabId = label === 'chrome' ? 9217 : 9218;
      const executed = [];
      let requestMessages = null;
      const provider = {
        supportsTools: true,
        supportsVision: false,
        promptTier: 'full',
        contextWindow: 128000,
        model: 'test-model',
        name: 'test-provider',
        chat: async (messages) => {
          requestMessages = messages;
          return { content: 'Summary from pre-read content.', toolCalls: [] };
        },
      };
      const agent = new AgentClass({
        getActive: () => provider,
        getVisionProvider: async () => null,
      });
      agent.planBeforeAct = false;
      agent.maxSteps = 1;
      agent._skipPermissionGate = true;
      agent._hydrate = async () => {};
      agent._manageContext = async () => {};
      agent._enrichUserMessageWithCurrentPage = async (_tabId, _messages, content) => ({ role: 'user', content });
      agent._maybeReinjectAdapter = async () => {};
      agent._persist = () => {};
      agent._startTraceRun = async () => null;
      agent._endTraceRun = () => {};
      agent.executeTool = async (_tabId, name, args) => {
        executed.push({ name, args });
        return { success: true, text: 'Article body from read_page.' };
      };

      const final = await agent.processMessage(
        tabId,
        'Summarize this page in bullets.',
        () => {},
        'ask',
        [],
        {
          recommendedAction: {
            id: 'summarize-page',
            autoExecute: true,
            tool: 'read_page',
            args: { includeChrome: false },
          },
        },
      );

      assert.equal(final, 'Summary from pre-read content.', `${label}: final response mismatch`);
      assert.deepEqual(executed, [{ name: 'read_page', args: { includeChrome: false } }], `${label}: first tool was not executed before LLM call`);
      const assistantToolIdx = requestMessages.findIndex((m) => m.role === 'assistant' && m.tool_calls?.[0]?.function?.name === 'read_page');
      const toolResultIdx = requestMessages.findIndex((m) => m.role === 'tool' && m.tool_call_id === 'recommended_summarize-page_first_tool');
      assert.ok(assistantToolIdx >= 0, `${label}: synthetic first-tool assistant call missing`);
      assert.equal(requestMessages[assistantToolIdx].tool_calls[0].type, 'function', `${label}: synthetic first-tool call should use OpenAI function tool-call shape`);
      assert.ok(toolResultIdx > assistantToolIdx, `${label}: first-tool result should precede first model answer`);
    }
  });
});

test('planner gate: skips one short follow-up after a newly approved try-mode plan', async () => {
  await withPlannerBrowserGlobals(async () => {
    for (const [label, AgentClass] of [['chrome', AgentCh], ['firefox', AgentFx]]) {
      const tabId = label === 'chrome' ? 9203 : 9204;
      const agent = new AgentClass({ getActive: () => ({}) });
      agent.setPlanBeforeActMode('try');
      agent.conversations.set(tabId, [{ role: 'system', content: 'system' }]);

      let plannerCalls = 0;
      agent._runPlannerGate = async () => {
        plannerCalls += 1;
        return plannerCalls === 1
          ? {
            proceed: true,
            approvedScratchpadText: '[Approved plan — pinned by planner]\n\n### Summary\nRevise the current draft.',
          }
          : { proceed: true };
      };

      const initial = await agent._maybeRunPlannerGate(
        tabId,
        agent.conversations.get(tabId),
        { role: 'user', content: 'help me revise this message' },
        () => {},
        'act',
        null,
        null,
      );

      assert.equal(initial.proceed, true, `${label} should proceed after approving the initial plan`);
      assert.equal(plannerCalls, 1, `${label} should run the planner for the initial act turn`);
      assert.equal(agent.plannerFollowUpSkipTabs.has(tabId), true, `${label} should arm one short follow-up skip`);

      const followUp = "you get the idea, just make it send ready BUT don't send";
      const enrichedFollowUp = `[Current page context — applies to this user message and supersedes older page context for phrases like "this page". URL: https://example.com/draft — Title: Draft]\n\n${followUp}`;
      const outcome = await agent._maybeRunPlannerGate(
        tabId,
        agent.conversations.get(tabId),
        { role: 'user', content: enrichedFollowUp },
        () => {},
        'act',
        null,
        null,
      );

      assert.equal(outcome.proceed, true, `${label} should proceed`);
      assert.equal(plannerCalls, 1, `${label} should not run a fresh planner call for a short planned follow-up`);
      assert.equal(agent.conversations.get(tabId).at(-1).content, enrichedFollowUp, `${label} should still append the enriched follow-up turn`);
      assert.equal(agent.plannerFollowUpSkipTabs.has(tabId), false, `${label} should consume the one short follow-up skip`);

      const secondFollowUp = await agent._maybeRunPlannerGate(
        tabId,
        agent.conversations.get(tabId),
        { role: 'user', content: 'same again' },
        () => {},
        'act',
        null,
        null,
      );

      assert.equal(secondFollowUp.proceed, true, `${label} second short follow-up should proceed`);
      assert.equal(plannerCalls, 2, `${label} second short follow-up should run the planner`);
      assert.equal(agent.plannerFollowUpSkipTabs.has(tabId), false, `${label} second short follow-up should not leave a skip armed`);
    }
  });
});

test('planner gate: short-follow-up skip keeps planner for stale, first, long, URL, attachment, and strict turns', async () => {
  await withPlannerBrowserGlobals(async () => {
    for (const [label, AgentClass] of [['chrome', AgentCh], ['firefox', AgentFx]]) {
      const scenarios = [
        {
          name: 'first short act',
          seedApprovedPlan: false,
          mode: 'try',
          message: { role: 'user', content: 'do it' },
        },
        {
          name: 'stale approved plan short follow-up',
          seedApprovedPlan: true,
          seedFollowUpSkip: false,
          mode: 'try',
          message: { role: 'user', content: 'do it' },
        },
        {
          name: 'long planned follow-up',
          seedApprovedPlan: true,
          seedFollowUpSkip: true,
          mode: 'try',
          message: { role: 'user', content: 'x'.repeat(101) },
        },
        {
          name: 'planned follow-up with URL',
          seedApprovedPlan: true,
          seedFollowUpSkip: true,
          mode: 'try',
          message: { role: 'user', content: 'open https://example.com' },
        },
        {
          name: 'planned follow-up with attachment block',
          seedApprovedPlan: true,
          seedFollowUpSkip: true,
          mode: 'try',
          message: {
            role: 'user',
            content: [
              { type: 'text', text: 'check this' },
              { type: 'image_url', image_url: { url: 'data:image/png;base64,AAA' } },
            ],
          },
        },
        {
          name: 'strict short planned follow-up',
          seedApprovedPlan: true,
          seedFollowUpSkip: true,
          mode: 'strict',
          message: { role: 'user', content: 'do it' },
        },
        {
          name: 'always-review short planned follow-up',
          seedApprovedPlan: true,
          seedFollowUpSkip: true,
          mode: 'try',
          reviewMode: 'always',
          message: { role: 'user', content: 'do it' },
        },
      ];

      for (const [index, scenario] of scenarios.entries()) {
        const tabId = (label === 'chrome' ? 9230 : 9240) + index;
        const agent = new AgentClass({ getActive: () => ({}) });
        agent.setPlanBeforeActMode(scenario.mode);
        if (scenario.reviewMode) agent.setPlanReviewSettings({ mode: scenario.reviewMode });
        const baseMessages = [
          { role: 'system', content: 'system' },
          { role: 'user', content: 'original task' },
        ];
        if (scenario.seedApprovedPlan) {
          baseMessages.push(agent._buildScratchpadMessage('[Approved plan — pinned by planner]\n\n### Summary\nOriginal plan.'));
        }
        agent.conversations.set(tabId, baseMessages);
        if (scenario.seedFollowUpSkip) agent.plannerFollowUpSkipTabs.add(tabId);

        let plannerCalls = 0;
        agent._runPlannerGate = async () => {
          plannerCalls += 1;
          return { proceed: true };
        };

        const outcome = await agent._maybeRunPlannerGate(
          tabId,
          agent.conversations.get(tabId),
          scenario.message,
          () => {},
          'act',
          null,
          null,
        );

        assert.equal(outcome.proceed, true, `${label}: ${scenario.name} should proceed`);
        assert.equal(plannerCalls, 1, `${label}: ${scenario.name} should run the planner`);
        assert.equal(agent.plannerFollowUpSkipTabs.has(tabId), false, `${label}: ${scenario.name} should clear any stale short-follow-up skip`);
      }
    }
  });
});

